parameters.query:
{{
  (() => {
    const raw = $json.message?.content ?? '';
    // quita cercas de código si vienen (```json, ```sql, ```)
    const clean = raw.replace(/```json|```sql|```/g, '').trim();
    try {
      const obj = JSON.parse(clean);
      return obj.query;           // usamos la clave "query" del JSON
    } catch (e) {
      return clean;               // si ya viene como SQL plano, úsalo tal cual
    }
  })()
}}

